{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを本日付で正式にキックオフし、正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例は毎週水曜日10時から1時間枠で開催し、各部署から少なくとも1名が参加する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "第1フェーズではトランザクション系データを移行せず、マスタ系データを先行移行し、過去の入出庫履歴は旧システムを参照用に残して対応する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "共通基盤の認証・マスタ配信はサクラ商事さんとの共同利用で進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "負荷テストの合格基準は、ピーク想定の負荷をかけた状態で午前中に共有した応答時間目標を満たすこととする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "障害発生時の一次受け窓口はQAチームとし、切り分けの一次対応をQAが担う。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "移行方式は拠点をグループ分けして順番に切り替える段階移行とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "本番リリース目標は9月末を撤回し、2026年10月15日に変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "切替作業は土曜深夜帯に実施する前提で進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D10",
      "content": "新システムのユーザー権限設計では既存のロール定義を流用し、新規のロール定義見直しは稼働後の運用改善として別扱いにする。",
      "decided_by": "芦田 巧"
    }
  ],
  "action_items": [
    {
      "id": "A1",
      "task": "API仕様書のドラフトを作成する。",
      "assignee": "芦田 巧",
      "due": "2026-05-20"
    },
